/**
 * pi-memory extension entry point.
 * Delegates all registration to src/extension/register.ts.
 */
import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { registerPiMemory } from "./src/extension/register.ts";

export default function (pi: ExtensionAPI): void {
	registerPiMemory(pi);
}

import * as fs from "node:fs";
import * as path from "node:path";

// ── Types ──────────────────────────────────────────────────────────────────────

export interface MentalModelsConfig {
	enabled: boolean;
	budgetChars: number;
	refreshInterval: number;
	seeds: string[];
}

export interface SearchConfig {
	maxResults: number;
	rrfK: number;
	proximityBoost: number;
	defaultDetail: "compact" | "medium" | "full";
}

export interface CompoundingConfig {
	enabled: boolean;
	dedupThreshold: number;
	categories: ("bug" | "knowledge" | "decision")[];
}

export interface ContinuityConfig {
	enabled: boolean;
	autoResume: boolean;
	maxResumeContext: number;
}

export interface PiMemoryConfig {
	enabled: boolean;
	autoCompound: boolean;
	autoGenerateSummary: boolean;
	maxSolutionsAge: number;
	maxEventsPerSession: number;
	recallBudget: number;
	mentalModels: MentalModelsConfig;
	search: SearchConfig;
	compounding: CompoundingConfig;
	continuity: ContinuityConfig;
}

// ── Defaults (per SPEC §11) ────────────────────────────────────────────────────

export const DEFAULT_CONFIG: PiMemoryConfig = {
	enabled: true,
	autoCompound: true,
	autoGenerateSummary: true,
	maxSolutionsAge: 90,
	maxEventsPerSession: 1000,
	recallBudget: 2048,
	mentalModels: {
		enabled: true,
		budgetChars: 16384,
		refreshInterval: 3,
		seeds: ["architecture", "testing-strategy", "data-flow", "conventions"],
	},
	search: {
		maxResults: 5,
		rrfK: 60,
		proximityBoost: 1.5,
		defaultDetail: "compact",
	},
	compounding: {
		enabled: true,
		dedupThreshold: 0.7,
		categories: ["bug", "knowledge", "decision"],
	},
	continuity: {
		enabled: true,
		autoResume: true,
		maxResumeContext: 1024,
	},
};

// ── Loader ─────────────────────────────────────────────────────────────────────

export function loadConfig(cwd: string): PiMemoryConfig {
	const configPath = path.join(cwd, ".pi", "pi-memory.json");
	try {
		if (fs.existsSync(configPath)) {
			const raw = fs.readFileSync(configPath, "utf-8");
			const parsed: unknown = JSON.parse(raw);
			if (typeof parsed === "object" && parsed !== null) {
				return deepMerge(DEFAULT_CONFIG, parsed as Partial<PiMemoryConfig>);
			}
		}
	} catch {
		// Fall through to defaults on parse error
	}
	return { ...DEFAULT_CONFIG };
}

function deepMerge<T extends Record<string, unknown>>(base: T, override: Partial<T>): T {
	const result = { ...base } as Record<string, unknown>;
	for (const key of Object.keys(override)) {
		const bv = base[key as keyof T];
		const ov = (override as Record<string, unknown>)[key];
		if (
			typeof bv === "object" && bv !== null && !Array.isArray(bv) &&
			typeof ov === "object" && ov !== null && !Array.isArray(ov)
		) {
			result[key] = deepMerge(
				bv as Record<string, unknown>,
				ov as Record<string, unknown>,
			);
		} else if (ov !== undefined) {
			result[key] = ov;
		}
	}
	return result as T;
}

import type Database from "better-sqlite3";

/**
 * Initialize all tables, indexes, and pragmas for the pi-memory database.
 * Safe to call multiple times — uses IF NOT EXISTS.
 */
export function initSchema(db: Database.Database): void {
	// Pragmas
	db.pragma("journal_mode = WAL");
	db.pragma("synchronous = NORMAL");
	db.pragma("cache_size = -64000");
	db.pragma("foreign_keys = ON");
	db.pragma("busy_timeout = 5000");

	// Sources: indexed content with metadata
	db.exec(`
		CREATE TABLE IF NOT EXISTS sources (
			id TEXT PRIMARY KEY,
			type TEXT NOT NULL,
			category TEXT,
			title TEXT,
			content_hash TEXT,
			file_path TEXT,
			created_at TEXT NOT NULL,
			updated_at TEXT NOT NULL,
			metadata TEXT
		);
	`);

	// FTS5 index: porter stemmer (conceptual search)
	db.exec(`
		CREATE VIRTUAL TABLE IF NOT EXISTS chunks USING fts5(
			source_id,
			title,
			content,
			category,
			tokenize="porter unicode61"
		);
	`);

	// FTS5 index: trigram (exact substring search)
	db.exec(`
		CREATE VIRTUAL TABLE IF NOT EXISTS chunks_trigram USING fts5(
			source_id,
			content,
			tokenize="trigram"
		);
	`);

	// Vocabulary: term frequency stats
	db.exec(`
		CREATE TABLE IF NOT EXISTS vocabulary (
			term TEXT PRIMARY KEY,
			doc_count INTEGER NOT NULL DEFAULT 0,
			total_count INTEGER NOT NULL DEFAULT 0
		);
	`);

	// Events: session tracking
	db.exec(`
		CREATE TABLE IF NOT EXISTS events (
			id INTEGER PRIMARY KEY AUTOINCREMENT,
			session_id TEXT,
			type TEXT NOT NULL,
			data TEXT NOT NULL,
			timestamp TEXT NOT NULL
		);
	`);

	// Solutions: compound knowledge
	db.exec(`
		CREATE TABLE IF NOT EXISTS solutions (
			id TEXT PRIMARY KEY,
			problem_type TEXT NOT NULL,
			category TEXT,
			title TEXT NOT NULL,
			content TEXT NOT NULL,
			files TEXT,
			tags TEXT,
			severity TEXT,
			overlap_hash TEXT,
			created_at TEXT NOT NULL,
			updated_at TEXT NOT NULL,
			access_count INTEGER DEFAULT 0,
			last_accessed_at TEXT
		);
	`);

	// Mental models: curated summaries
	db.exec(`
		CREATE TABLE IF NOT EXISTS mental_models (
			id TEXT PRIMARY KEY,
			name TEXT NOT NULL UNIQUE,
			content TEXT NOT NULL,
			source_ids TEXT,
			budget_chars INTEGER DEFAULT 16384,
			auto_refreshed_at TEXT,
			created_at TEXT NOT NULL,
			updated_at TEXT NOT NULL
		);
	`);

	// Performance indexes
	db.exec(`CREATE INDEX IF NOT EXISTS idx_sources_type ON sources(type);`);
	db.exec(`CREATE INDEX IF NOT EXISTS idx_sources_category ON sources(category);`);
	db.exec(`CREATE INDEX IF NOT EXISTS idx_sources_file_path ON sources(file_path);`);
	db.exec(`CREATE INDEX IF NOT EXISTS idx_sources_content_hash ON sources(content_hash);`);
	db.exec(`CREATE INDEX IF NOT EXISTS idx_events_session ON events(session_id);`);
	db.exec(`CREATE INDEX IF NOT EXISTS idx_events_type ON events(type);`);
	db.exec(`CREATE INDEX IF NOT EXISTS idx_events_timestamp ON events(timestamp);`);
	db.exec(`CREATE INDEX IF NOT EXISTS idx_solutions_problem ON solutions(problem_type);`);
	db.exec(`CREATE INDEX IF NOT EXISTS idx_solutions_severity ON solutions(severity);`);
}

import * as fs from "node:fs";
import * as path from "node:path";
import BetterSqlite3 from "better-sqlite3";
import type Database from "better-sqlite3";
import { initSchema } from "./schema.ts";

/**
 * Manages the SQLite database connection for pi-memory.
 * Database is stored at <cwd>/.pi-memory/memory.db.
 */
export class MemoryDB {
	public readonly dbPath: string;
	private db: Database.Database | null = null;

	constructor(public readonly cwd: string) {
		const dir = path.join(cwd, ".pi-memory");
		fs.mkdirSync(dir, { recursive: true });
		this.dbPath = path.join(dir, "memory.db");
	}

	/** Open (or return existing) database connection with full schema. */
	open(): Database.Database {
		if (this.db) return this.db;
		this.db = new BetterSqlite3(this.dbPath) as unknown as Database.Database;
		initSchema(this.db);
		return this.db;
	}

	/** Get the current open connection (throws if not open). */
	getConnection(): Database.Database {
		if (!this.db) throw new Error("MemoryDB not opened. Call open() first.");
		return this.db;
	}

	/** Close the database connection. */
	close(): void {
		if (this.db) {
			try {
				this.db.close();
			} catch {
				// Ignore close errors
			}
			this.db = null;
		}
	}

	/** Check if the database is currently open. */
	get isOpen(): boolean {
		return this.db !== null;
	}
}

